   507→        );
   508→
   509→        println!("Enhanced summary statistics:");
   510→        println!("R² = {:.6}", summary.r_squared);
   511→        println!("Adj R² = {:.6}", summary.adj_r_squared);
   512→        println!("Residual SE = {:.6}", summary.residual_std_error);
   513→        println!("F-statistic = {:.6}", summary.f_statistic);
   514→        println!("F p-value = {:.6}", summary.f_p_value);
   515→    }
